import{_ as c,o as a,c as o,a3 as d}from"./chunks/framework.aYYe0dfI.js";const h=JSON.parse('{"title":"Module extract:scan","description":"extract:scan 模块是 clore::extract 中负责 C++ 源文件依赖关系扫描与模块信息提取的核心模块。它通过 Clang 的预处理指令扫描器（scan_module_decl）快速获取模块声明、接口单元标识和导入列表，并可基于完整编译数据库对单个文件进行深层扫描（scan_file），返回包含模块名称、导入、包含指令及错误的 ScanResult。同时，该模块支持异步构建模块间的 DependencyGraph（通过 build_dependency_graph_async），并提供了 topological_order 函数对图进行拓扑排序，为后续编译或分析提供有序的依赖列表。","frontmatter":{"title":"Module extract:scan","description":"extract:scan 模块是 clore::extract 中负责 C++ 源文件依赖关系扫描与模块信息提取的核心模块。它通过 Clang 的预处理指令扫描器（scan_module_decl）快速获取模块声明、接口单元标识和导入列表，并可基于完整编译数据库对单个文件进行深层扫描（scan_file），返回包含模块名称、导入、包含指令及错误的 ScanResult。同时，该模块支持异步构建模块间的 DependencyGraph（通过 build_dependency_graph_async），并提供了 topological_order 函数对图进行拓扑排序，为后续编译或分析提供有序的依赖列表。","layout":"doc","template":"doc"},"headers":[],"relativePath":"zh/clore/modules/extract/scan.md","filePath":"zh/clore/modules/extract/scan.md"}'),t={name:"zh/clore/modules/extract/scan.md"};function r(l,e,n,i,s,u){return a(),o("div",null,[...e[0]||(e[0]=[d('<h1 id="module-extract-scan" tabindex="-1">Module <code>extract:scan</code> <a class="header-anchor" href="#module-extract-scan" aria-label="Permalink to &quot;Module `extract:scan`&quot;">​</a></h1><h2 id="summary" tabindex="-1">Summary <a class="header-anchor" href="#summary" aria-label="Permalink to &quot;Summary&quot;">​</a></h2><p><code>extract:scan</code> 模块是 <code>clore::extract</code> 中负责 C++ 源文件依赖关系扫描与模块信息提取的核心模块。它通过 Clang 的预处理指令扫描器（<code>scan_module_decl</code>）快速获取模块声明、接口单元标识和导入列表，并可基于完整编译数据库对单个文件进行深层扫描（<code>scan_file</code>），返回包含模块名称、导入、包含指令及错误的 <code>ScanResult</code>。同时，该模块支持异步构建模块间的 <code>DependencyGraph</code>（通过 <code>build_dependency_graph_async</code>），并提供了 <code>topological_order</code> 函数对图进行拓扑排序，为后续编译或分析提供有序的依赖列表。</p><p>在公开的实现范围上，该模块定义了 <code>ScanResult</code>、<code>ScanError</code>、<code>ScanCache</code>、<code>DependencyGraph</code>、<code>DependencyEdge</code> 以及 <code>IncludeInfo</code> 等核心数据结构。<code>ScanCache</code> 作为跨次扫描的持久缓存，可避免重复解析相同文件；而依赖图构建过程利用 <code>MissingScanTask</code>、<code>PreparedScanEntry</code> 等内部机制高效管理未扫描任务。调用者应通过上述公开接口触发扫描流程，并根据返回的结果或错误信息进行后续处理，同时注意在文件系统或编译数据库变更时清除缓存以保证数据一致性。</p><h2 id="imports" tabindex="-1">Imports <a class="header-anchor" href="#imports" aria-label="Permalink to &quot;Imports&quot;">​</a></h2><ul><li><a href="./compiler"><code>extract:compiler</code></a></li><li><code>std</code></li><li><a href="./../support/"><code>support</code></a></li></ul><h2 id="imported-by" tabindex="-1">Imported By <a class="header-anchor" href="#imported-by" aria-label="Permalink to &quot;Imported By&quot;">​</a></h2><ul><li><a href="./cache"><code>extract:cache</code></a></li></ul><h2 id="types" tabindex="-1">Types <a class="header-anchor" href="#types" aria-label="Permalink to &quot;Types&quot;">​</a></h2><h3 id="clore-extract-dependencyedge" tabindex="-1"><code>clore::extract::DependencyEdge</code> <a class="header-anchor" href="#clore-extract-dependencyedge" aria-label="Permalink to &quot;`clore::extract::DependencyEdge`&quot;">​</a></h3><p>Declaration: <code>extract/scan.cppm:51</code></p><p>Definition: <code>extract/scan.cppm:51</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>The struct <code>clore::extract::DependencyEdge</code> stores a directed dependency edge using two <code>std::string</code> members: <code>clore::extract::DependencyEdge::from</code> and <code>clore::extract::DependencyEdge::to</code>. No invariants are enforced beyond the usual validity of the string values; the edge is represented purely by these two named fields, and the struct relies on implicitly defined special member functions for construction, copy, and move operations. The absence of user‑defined constructors or member functions means that the two strings can be set directly, and the struct is trivially aggregate‑initializable.</p><h4 id="invariants" tabindex="-1">Invariants <a class="header-anchor" href="#invariants" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>The struct has exactly two <code>std::string</code> members: <code>from</code> and <code>to</code>.</li><li>Both members are publicly accessible.</li></ul><h4 id="key-members" tabindex="-1">Key Members <a class="header-anchor" href="#key-members" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>from</code>: the source node identifier.</li><li><code>to</code>: the target node identifier.</li></ul><h4 id="usage-patterns" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used in the <code>clore::extract</code> module to represent dependencies between extracted symbols.</li><li>Edges are combined into lists or sets to form dependency graphs.</li></ul><h3 id="clore-extract-dependencygraph" tabindex="-1"><code>clore::extract::DependencyGraph</code> <a class="header-anchor" href="#clore-extract-dependencygraph" aria-label="Permalink to &quot;`clore::extract::DependencyGraph`&quot;">​</a></h3><p>Declaration: <code>extract/scan.cppm:56</code></p><p>Definition: <code>extract/scan.cppm:56</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p><code>clore::extract::DependencyGraph</code> 使用简单的边列表表示来存储依赖关系图。其核心数据是两个平行的 <code>std::vector</code>：<code>files</code> 存放所有被扫描的源文件路径（作为 <code>std::string</code>），而 <code>edges</code> 存放由 <code>DependencyEdge</code> 实例描述的依赖边。每条边隐含地关联 <code>files</code> 中的两个元素（通常通过索引或字符串引用），形成有向依赖关系。这种结构避免了复杂的邻接表，便于序列化并对所有依赖进行线性遍历，但查找特定节点或逆依赖时需要扫描整个 <code>edges</code> 向量。</p><h4 id="invariants-1" tabindex="-1">Invariants <a class="header-anchor" href="#invariants-1" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>Each element in <code>edges</code> references indices or paths in <code>files</code> (implied by typical dependency graph usage, but not explicitly guaranteed by the evidence).</li></ul><h4 id="key-members-1" tabindex="-1">Key Members <a class="header-anchor" href="#key-members-1" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>files</code>: a <code>std::vector&lt;std::string&gt;</code> of file paths.</li><li><code>edges</code>: a <code>std::vector&lt;DependencyEdge&gt;</code> of dependency relationships.</li></ul><h4 id="usage-patterns-1" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-1" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used to represent the complete dependency information extracted from source files.</li><li>Consumed by downstream analysis or transformation passes.</li></ul><h3 id="clore-extract-includeinfo" tabindex="-1"><code>clore::extract::IncludeInfo</code> <a class="header-anchor" href="#clore-extract-includeinfo" aria-label="Permalink to &quot;`clore::extract::IncludeInfo`&quot;">​</a></h3><p>Declaration: <code>extract/scan.cppm:24</code></p><p>Definition: <code>extract/scan.cppm:24</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p><code>clore::extract::IncludeInfo</code> 是一个简单的值类型，用于封装一个 include 指令的解析结果。其内部由两个公有成员组成：<code>path</code> 是一个 <code>std::string</code>，默认初始化为空字符串，存储被包含文件的路径；<code>is_angled</code> 是一个 <code>bool</code>，默认初始化为 <code>false</code>，指示该 include 使用的是尖括号形式（<code>&lt;...&gt;</code>）还是引号形式（<code>&quot;...&quot;</code>）。该结构体没有自定义构造函数或成员函数，所有操作完全依赖默认成员初始化。由于其成员均为公有且直接可写，外部代码可在解析过程中独立设置每个字段，无需保持任何内部一致性的额外步骤。唯一的隐含不变量是 <code>path</code> 的内容应为一个合法的文件路径（或为空），但该条件并非由类型本身强制。</p><h4 id="invariants-2" tabindex="-1">Invariants <a class="header-anchor" href="#invariants-2" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>The <code>path</code> member holds the include path as specified in the source</li><li>The <code>is_angled</code> member distinguishes between <code>#include &lt;...&gt;</code> (true) and <code>#include &quot;...&quot;</code> (false)</li></ul><h4 id="key-members-2" tabindex="-1">Key Members <a class="header-anchor" href="#key-members-2" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>path</code></li><li><code>is_angled</code></li></ul><h4 id="usage-patterns-2" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-2" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Created when parsing include directives from source code</li><li>Used to reconstruct or analyze include statements</li></ul><h3 id="clore-extract-scancache" tabindex="-1"><code>clore::extract::ScanCache</code> <a class="header-anchor" href="#clore-extract-scancache" aria-label="Permalink to &quot;`clore::extract::ScanCache`&quot;">​</a></h3><p>Declaration: <code>extract/scan.cppm:40</code></p><p>Definition: <code>extract/scan.cppm:40</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>结构体 <code>clore::extract::ScanCache</code> 的内部实现是一个简单的包装，其唯一的数据成员是 <code>std::unordered_map&lt;std::string, ScanResult&gt; scan_results</code>。该映射将扫描对象的标识符（通常为文件路径）与被缓存的分析结果相关联，从而避免在连续依赖扫描中重复执行代价高昂的文件解析。实现层面没有任何额外的同步或生命周期管理；调用者必须遵从约定的不变性：当编译数据库或文件系统状态发生变化时，必须通过丢弃或清空整个 <code>ScanCache</code> 实例来强制失效，否则映射中陈旧的 <code>ScanResult</code> 条目可能导致错误的扫描结果。<code>scan_results</code> 默认初始化为空映射，插入和查找完全依赖标准库的无序映射行为。</p><h4 id="invariants-3" tabindex="-1">Invariants <a class="header-anchor" href="#invariants-3" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>Cache entries are valid only as long as the compilation database and file system state remain unchanged.</li><li>The map key uniquely identifies a scan target (e.g., source file or header).</li><li>The cache should be cleared or replaced when external state changes.</li></ul><h4 id="key-members-3" tabindex="-1">Key Members <a class="header-anchor" href="#key-members-3" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>scan_results</code>: the underlying hash map storing cached scan results.</li></ul><h4 id="usage-patterns-3" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-3" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Used by scan functions to avoid redundant re‑scanning of unchanged input files.</li><li>Callers are responsible for clearing or discarding the cache when the compilation DB or file system is modified.</li><li>Typically passed by reference to scan utilities so that results accumulate across multiple calls.</li></ul><h3 id="clore-extract-scanerror" tabindex="-1"><code>clore::extract::ScanError</code> <a class="header-anchor" href="#clore-extract-scanerror" aria-label="Permalink to &quot;`clore::extract::ScanError`&quot;">​</a></h3><p>Declaration: <code>extract/scan.cppm:20</code></p><p>Definition: <code>extract/scan.cppm:20</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>该结构体被实现为一个简单的聚合类型，仅包含一个 <code>std::string</code> 类型的 <code>message</code> 成员，用于保存扫描过程中产生的错误描述。不要求任何特殊的构造、赋值或析构逻辑，因为 <code>std::string</code> 本身负责内存管理并满足值语义。不变量方面，<code>message</code> 可能为空字符串以表示无具体错误，但该行为取决于构造和赋值处；没有额外的约束由结构体自身强制。实现上不涉及虚函数、继承或自定义内存分配器，因此实例的生存期和复制完全由标准字符串的规则决定。</p><h4 id="key-members-4" tabindex="-1">Key Members <a class="header-anchor" href="#key-members-4" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>message</code> field (type <code>std::string</code>)</li></ul><h3 id="clore-extract-scanresult" tabindex="-1"><code>clore::extract::ScanResult</code> <a class="header-anchor" href="#clore-extract-scanresult" aria-label="Permalink to &quot;`clore::extract::ScanResult`&quot;">​</a></h3><p>Declaration: <code>extract/scan.cppm:29</code></p><p>Definition: <code>extract/scan.cppm:29</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p><code>clore::extract::ScanResult</code> 是扫描器输出的聚合结构，内部通过四个字段组装模块元数据。<code>module_name</code> 记录当前扫描单元的名称，<code>is_interface_unit</code> 标记是否为模块接口单元，两者配合标识模块身份。<code>includes</code> 存储扫描过程中收集的所有 <code>IncludeInfo</code> 条目，<code>module_imports</code> 记录该单元导入的其他模块名列表；两个容器在扫描完成后应保持完整且无重复项。结构体直接暴露所有字段，未定义构造函数或成员函数，因此字段初始值（空字符串、<code>false</code>、空向量）构成了正确的默认不变量——未扫描或扫描失败时返回的 <code>ScanResult</code> 应处于该干净状态。</p><h4 id="invariants-4" tabindex="-1">Invariants <a class="header-anchor" href="#invariants-4" aria-label="Permalink to &quot;Invariants&quot;">​</a></h4><ul><li>All vectors are properly initialized (default-constructed empty).</li><li><code>module_name</code> is a valid empty or non-empty string.</li><li><code>is_interface_unit</code> is either <code>true</code> or <code>false</code>.</li></ul><h4 id="key-members-5" tabindex="-1">Key Members <a class="header-anchor" href="#key-members-5" aria-label="Permalink to &quot;Key Members&quot;">​</a></h4><ul><li><code>module_name</code></li><li><code>is_interface_unit</code></li><li><code>includes</code></li><li><code>module_imports</code></li></ul><h4 id="usage-patterns-4" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-4" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Returned from scanning functions to represent the parsed module data.</li><li>Inspected by callers to access the module name, imports, includes, and interface status.</li></ul><h2 id="functions" tabindex="-1">Functions <a class="header-anchor" href="#functions" aria-label="Permalink to &quot;Functions&quot;">​</a></h2><h3 id="clore-extract-build-dependency-graph-async" tabindex="-1"><code>clore::extract::build_dependency_graph_async</code> <a class="header-anchor" href="#clore-extract-build-dependency-graph-async" aria-label="Permalink to &quot;`clore::extract::build_dependency_graph_async`&quot;">​</a></h3><p>Declaration: <code>extract/scan.cppm:61</code></p><p>Definition: <code>extract/scan.cppm:370</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>函数首先清空 <code>graph.files</code> 和 <code>graph.edges</code>，然后遍历 <code>db.entries</code>，对每个条目调用 <code>prepare_scan_entry</code> 得到 <code>PreparedScanEntry</code>，将其 <code>normalized_file</code> 加入 <code>graph.files</code> 并存入 <code>prepared_entries</code>。接着利用 <code>cache</code> 中的 <code>scan_results</code> 查找每个条目的 <code>cache_key</code>：若命中则记录在 <code>cached_results</code> 中；否则将未命中的条目按 <code>cache_key</code> 去重后构造 <code>MissingScanTask</code> 列表，并通过 <code>missing_task_indices</code> 记录每个条目在缺失任务中的索引。随后并发运行所有缺失任务的异步扫描（<code>kota::when_all</code>），等待结果并处理可能的 <code>ScanError</code>。</p><p>处理完所有扫描结果后，函数再次遍历每个数据库条目，根据 <code>cached_results</code> 或 <code>scanned_results</code> 获取对应的 <code>ScanResult</code>。对每个文件的 <code>result.includes</code>，将包含路径规范化后，若该路径存在于 <code>entry_files</code> 集合中，则构造一条从当前文件 <code>normalized</code> 到包含文件 <code>inc_normalized</code> 的 <code>DependencyEdge</code>，并通过 <code>emitted_edges</code> 集合去重。最后，若 <code>cache</code> 非空，则将本次获得的 <code>ScanResult</code> 写回 <code>cache-&gt;scan_results</code> 以供后续复用。</p><h4 id="side-effects" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>clears <code>graph.files</code> and <code>graph.edges</code></li><li>pushes file paths into <code>graph.files</code></li><li>pushes <code>DependencyEdge</code> objects into <code>graph.edges</code></li><li>inserts or assigns scan results into <code>scan_results</code> map when cache is non-null</li></ul><h4 id="reads-from" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>db.entries</code></li><li><code>prepared_entries[idx]</code> fields including <code>normalized_file</code>, <code>cache_key</code></li><li><code>entry.directory</code></li><li><code>scan_result-&gt;includes</code></li><li><code>scan_results-&gt;find(cache_key)</code></li></ul><h4 id="writes-to" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li><code>graph.files</code></li><li><code>graph.edges</code></li><li><code>scan_results</code> map (via <code>insert_or_assign</code>)</li></ul><h4 id="usage-patterns-5" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-5" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>called to asynchronously construct a dependency graph before topological ordering</li><li>used in build or analysis pipelines where concurrency is needed</li><li>invoked with a <code>ScanCache*</code> to accelerate repeated scans</li></ul><h3 id="clore-extract-scan-file" tabindex="-1"><code>clore::extract::scan_file</code> <a class="header-anchor" href="#clore-extract-scan-file" aria-label="Permalink to &quot;`clore::extract::scan_file`&quot;">​</a></h3><p>Declaration: <code>extract/scan.cppm:44</code></p><p>Definition: <code>extract/scan.cppm:238</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>函数 <code>clore::extract::scan_file</code> 首先检查 <code>entry.arguments</code> 是否为空，若为空则立即返回包含错误信息的 <code>std::unexpected&lt;ScanError&gt;</code>。随后，它通过标准化路径读取源文件内容，并调用 <code>scan_module_decl</code> 快速扫描模块声明，填充 <code>ScanResult</code> 中的模块名称和接口单元标识。接着，函数创建一个编译器实例，并将预处理动作设为仅运行预处理器，然后构造 <code>ScanAction</code> 对象（关联同一个 <code>ScanResult</code>），依次调用 <code>BeginSourceFile</code> 和 <code>Execute</code> 执行实际的预处理扫描，借助 <code>ScanPPCallbacks</code> 收集包含指令、导入声明等依赖信息。若任何步骤失败（如文件读取错误、编译器实例创建失败、预处理执行错误），函数都会以对应的 <code>ScanError</code> 提前返回；成功时则返回填充完整的 <code>ScanResult</code>。整个流程依赖 <code>scan_module_decl</code> 进行快速模块声明扫描，并依赖编译器基础设施（<code>clang::CompilerInstance</code>、<code>ScanAction</code>）完成预处理阶段的依赖解析。</p><h4 id="side-effects-1" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-1" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Reads source file from disk</li><li>Creates a Clang compiler instance (may query toolchain cache)</li><li>Mutates the <code>ScanResult</code> object passed by reference inside <code>ScanAction</code></li><li>Calls <code>scan_module_decl</code> which modifies <code>ScanResult</code></li><li>Executes Clang preprocessor, which may produce diagnostic output</li><li>Consumes LLVM errors via <code>llvm::consumeError</code></li></ul><h4 id="reads-from-1" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-1" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>entry</code> compilation entry parameters</li><li>Source file on disk (via <code>std::ifstream</code>)</li><li>Toolchain cache (via <code>create_compiler_instance</code>)</li></ul><h4 id="writes-to-1" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-1" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li><code>result</code> local variable of type <code>ScanResult</code> (populated with symbol information)</li><li>Compiler instance frontend options (sets <code>ProgramAction</code>, clears output paths)</li><li>LLVM error handling (consumes error)</li></ul><h4 id="usage-patterns-6" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-6" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called for each file in a compilation database during project scanning</li><li>Used as the primary entry point for extracting symbols from a single translation unit</li></ul><h3 id="clore-extract-scan-module-decl" tabindex="-1"><code>clore::extract::scan_module_decl</code> <a class="header-anchor" href="#clore-extract-scan-module-decl" aria-label="Permalink to &quot;`clore::extract::scan_module_decl`&quot;">​</a></h3><p>Declaration: <code>extract/scan.cppm:49</code></p><p>Definition: <code>extract/scan.cppm:141</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>Implementation: <a href="./functions/scan-module-decl">Implementation</a></p><p>函数 <code>clore::extract::scan_module_decl</code> 利用 Clang 的依赖指令扫描器（<code>clang::scanSourceForDependencyDirectives</code>）对给定的文件内容进行快速模块声明分析，避免运行完整预处理器。内部首先将源文本解析为 <code>tokens</code> 和 <code>directives</code> 向量；若扫描失败则直接返回，不修改 <code>ScanResult</code>。随后遍历每个指令：对于 <code>cxx_export_module_decl</code> 或 <code>cxx_module_decl</code> 类型的指令，跳过 <code>export</code> 和 <code>module</code> 关键字，通过收集后续标识符（排除空白和纯标点）构建模块名称，并据此设置 <code>result.module_name</code> 和 <code>result.is_interface_unit</code>（仅 <code>export module</code> 表示接口单元）；对于 <code>cxx_import_decl</code> 类型的指令，跳过 <code>import</code> 关键字后收集导入名称，调用 <code>normalize_partition_import</code> 进行规范化，并在去重后加入 <code>result.module_imports</code>。该函数依赖 <code>ScanResult</code> 结构体字段和 <code>normalize_partition_import</code> 辅助函数，同时借助两个内联 lambda（<code>is_whitespace_only</code> 和 <code>is_punctuation_only</code>）辅助令牌分类。</p><h4 id="side-effects-2" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-2" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><ul><li>Modifies the <code>ScanResult</code> parameter by setting <code>module_name</code>, <code>is_interface_unit</code>, and <code>module_imports</code>.</li><li>Allocates memory for <code>std::string</code> and <code>std::vector</code> members of <code>ScanResult</code>.</li></ul><h4 id="reads-from-2" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-2" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li><code>file_content</code> (<code>string_view</code>) - source text of a translation unit.</li><li><code>result</code> (<code>ScanResult</code>&amp;) - reads <code>module_name</code> and <code>module_imports</code> for duplicate checking.</li><li>Directives and tokens produced by <code>clang::scanSourceForDependencyDirectives</code>.</li></ul><h4 id="writes-to-2" tabindex="-1">Writes To <a class="header-anchor" href="#writes-to-2" aria-label="Permalink to &quot;Writes To&quot;">​</a></h4><ul><li><code>result.module_name</code> - set to the extracted module name.</li><li><code>result.is_interface_unit</code> - set to <code>true</code> if <code>export module</code> declaration, else <code>false</code>.</li><li><code>result.module_imports</code> - appended with normalized import names.</li></ul><h4 id="usage-patterns-7" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-7" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called by <code>clore::extract::scan_file</code> to perform fast module scanning on source files.</li><li>Used as a lightweight alternative to full preprocessing for module dependency discovery.</li></ul><h3 id="clore-extract-topological-order" tabindex="-1"><code>clore::extract::topological_order</code> <a class="header-anchor" href="#clore-extract-topological-order" aria-label="Permalink to &quot;`clore::extract::topological_order`&quot;">​</a></h3><p>Declaration: <code>extract/scan.cppm:66</code></p><p>Definition: <code>extract/scan.cppm:495</code></p><p>Declaration: <a href="./../../namespaces/clore/extract/"><code>Namespace clore::extract</code></a></p><p>该函数从给定的 <code>DependencyGraph</code> 中提取 <code>graph.files</code> 的拓扑顺序。首先，它为每个文件名初始化一个零入度的映射 <code>in_degree</code>。然后，遍历 <code>graph.edges</code>，对于每条边，将 <code>edge.to</code> 作为邻接键，将 <code>edge.from</code> 追加到 <code>adj[edge.to]</code> 中，并递增 <code>in_degree[edge.from]</code>，从而构建一个有向图：入边从依赖者指向被依赖者，即 <code>edge.from</code> 依赖于 <code>edge.to</code>。之后，将 <code>graph.files</code>、<code>adj</code> 和 <code>in_degree</code> 转发给 <code>clore::support::topological_order</code> 执行标准的 Kahn 算法。若该调用返回无值，则函数返回一个包含描述性消息的 <code>ScanError</code>，表明检测到循环依赖；否则返回计算得到的顺序向量。整个过程完全依赖于 <code>DependencyGraph</code> 的数据结构以及通用排序工具，不涉及任何扫描或预处理逻辑。</p><h4 id="side-effects-3" tabindex="-1">Side Effects <a class="header-anchor" href="#side-effects-3" aria-label="Permalink to &quot;Side Effects&quot;">​</a></h4><p>No observable side effects are evident from the extracted code.</p><h4 id="reads-from-3" tabindex="-1">Reads From <a class="header-anchor" href="#reads-from-3" aria-label="Permalink to &quot;Reads From&quot;">​</a></h4><ul><li>const <code>DependencyGraph</code>&amp; graph (graph<code>.files</code>, graph<code>.edges</code>)</li></ul><h4 id="usage-patterns-8" tabindex="-1">Usage Patterns <a class="header-anchor" href="#usage-patterns-8" aria-label="Permalink to &quot;Usage Patterns&quot;">​</a></h4><ul><li>Called after building a dependency graph to determine a valid compilation order</li><li>Used to detect cycles in the include graph</li></ul><h2 id="internal-structure" tabindex="-1">Internal Structure <a class="header-anchor" href="#internal-structure" aria-label="Permalink to &quot;Internal Structure&quot;">​</a></h2><p><code>extract:scan</code> 模块负责 C++ 模块文件的依赖扫描和依赖图构建。其核心分解为：公开的扫描入口 <code>scan_file</code> 和 <code>scan_module_decl</code> 分别执行完整扫描和快速模块声明扫描；异步构建依赖图的 <code>build_dependency_graph_async</code> 以及拓扑排序 <code>topological_order</code> 构成高层工作流。内部实现利用匿名命名空间隔离具体细节，包括 <code>ScanAction</code>（管理一次扫描的预处理器回调）、<code>ScanPPCallbacks</code>（捕获 <code>#include</code> 和模块导入指令）、<code>PreparedScanEntry</code>（缓存键和归一化路径准备）以及 <code>MissingScanTask</code>（表示需扫描的缺失文件）。依赖方面，模块导入 <code>extract:compiler</code> 获取编译数据库信息，并依赖 <code>support</code> 模块提供的文件读写、路径归一化和缓存键生成等基础工具。</p><p>模块内部按职责分为三层：底层为 <code>scan_module_decl</code> 和 <code>ScanPPCallbacks</code> 实现的词法和预处理回调逻辑；中层由 <code>scan_file</code> 和 <code>run_scan_task</code> 协调条目扫描，并利用 <code>ScanCache</code> 持久化重复扫描结果；顶层是依赖图构建——<code>build_dependency_graph_async</code> 通过事件循环 <code>kota::event_loop</code> 调度 <code>MissingScanTask</code>，将扫描结果填充至 <code>DependencyGraph</code>（包含文件列表和依赖边），最后 <code>topological_order</code> 对图进行拓扑排序。缓存机制贯穿各层：<code>ScanCache</code> 缓存 <code>ScanResult</code>，通过 <code>cache_key</code> 和 <code>compile_signature</code> 实现快速命中，避免重复解析。实现结构清晰分离了同步扫描、异步调度和图构建的关注点。</p><h2 id="related-pages" tabindex="-1">Related Pages <a class="header-anchor" href="#related-pages" aria-label="Permalink to &quot;Related Pages&quot;">​</a></h2><ul><li><a href="./compiler">Module extract:compiler</a></li><li><a href="./../support/">Module support</a></li></ul>',129)])])}const m=c(t,[["render",r]]);export{h as __pageData,m as default};
